import { isUndefined } from 'lodash-es';

import { formatDateRange } from './format-date-range.js';
import { isDateRange, isNonEmptyRange, isSingleValue } from './type-guards.js';
import type { HeaderData } from '../../../types.js';

export const getSingleValue = (value: HeaderData): string => {
  const rawValue = Array.isArray(value) ? value[0] : value;
  return isUndefined(rawValue) ? '' : rawValue.toString();
};

export const defaultLabelFormatterStrategy = (
  value: HeaderData,
  label?: string,
): string => {
  if (isSingleValue(value)) {
    const returnValue = getSingleValue(value);
    return label ? `${label}: ${returnValue}` : returnValue.toString();
  }
  return formatValueRange(value);
};

export const emptyHeaderFormatter = (_: HeaderData): null => {
  return null;
};

export const formatValueRange = (values: HeaderData): string => {
  if (isNonEmptyRange(values)) {
    let base = `${values[0]} - ${values[1]}`;

    if (isDateRange(values)) {
      base = formatDateRange(values[0], values[1]);
    }

    return base;
  }

  if (!Array.isArray(values)) {
    return !isUndefined(values) ? defaultLabelFormatterStrategy(values) : '';
  }

  if (values.some((i) => !isUndefined(i))) {
    return defaultLabelFormatterStrategy(values[0] ?? values[1]);
  }

  return '';
};
